self.addEventListener("push",t=>{let i={title:"ЛегкоСохранить.рф",body:"У вас новое уведомление!",url:"/"};if(t.data)try{i=t.data.json()}catch(e){i.body=t.data.text()}let e={body:i.body,icon:"/logo.png",badge:"/favicon.svg",vibrate:[100,50,100],data:{url:i.url||"/"}};t.waitUntil(self.registration.showNotification(i.title,e))}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=new URL(t.notification.data.url,self.location.origin).href,e=clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{let e=null;for(let l=0;l<t.length;l++){let n=t[l];if(n.url===i){e=n;break}}return e?e.focus():clients.openWindow(i)});t.waitUntil(e)});